"use strict";(globalThis.webpackChunkalvarolorente_dev=globalThis.webpackChunkalvarolorente_dev||[]).push([[7992],{9297(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>s,default:()=>d,frontMatter:()=>o,metadata:()=>i,toc:()=>h});var i=n(4897),r=n(4848),a=n(8453);const o={title:"Our Engineering Metrics Are About to Get Even More Misleading in the Age of AI",description:"The more AI increases visible activity, the less visible activity tells us about real engineering performance.",authors:"alvarolorentedev",tags:["substack"],draft:!1,series:"",canonical_url:"https://theengineeringtax.com/p/our-metrics-are-about-to-get-even",cover_image:null},s=void 0,l={authorsImageUrls:[void 0]},h=[{value:"Your dashboard is probably measuring the wrong layer",id:"your-dashboard-is-probably-measuring-the-wrong-layer",level:2},{value:"What engineering leaders and teams should measure now",id:"what-engineering-leaders-and-teams-should-measure-now",level:2},{value:"The Uncomfortable Reality &amp; How-To Survive It",id:"the-uncomfortable-reality--how-to-survive-it",level:2}];function c(e){const t={h2:"h2",p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsxs)(t.p,{children:["T",(0,r.jsx)(t.strong,{children:"he more AI increases visible activity, the less visible activity tells us about real engineering performance."})]}),"\n",(0,r.jsx)(t.p,{children:"For years, engineering organizations have had a quiet habit: we measured what was easiest to count, then convinced ourselves it was what mattered."}),"\n",(0,r.jsx)(t.p,{children:"Tickets closed. Story points completed. Pull requests merged. Deployments made. Features shipped."}),"\n",(0,r.jsx)(t.p,{children:"None of these signals were completely useless. But many of them were weak proxies for value. They gave leaders the comfort of visibility without the discipline of understanding. They made dashboards look precise while leaving the real questions unanswered."}),"\n",(0,r.jsx)(t.p,{children:"Did the work reduce risk? Did it improve reliability? Did it create customer value? Did it lower cognitive load for the team? Did it save us from future rework, or simply postpone it?"}),"\n",(0,r.jsx)(t.p,{children:"This was already a problem before AI. It did not create that weakness. It exposed it."}),"\n",(0,r.jsx)(t.p,{children:"Because once code, tests, documentation, refactors, and implementation options become dramatically easier to generate, visible activity stops being scarce. And once visible activity stops being scarce, visible activity stops being persuasive."}),"\n",(0,r.jsx)(t.p,{children:"That is the shift many engineering leaders are about to miss."}),"\n",(0,r.jsx)(t.p,{children:"The old scoreboard still measures motion. But AI changes the meaning of motion. A team can now generate more output than ever before and still create more instability, more review burden, more hidden rework, and more downstream coordination cost. DORA remains useful precisely because it never treated throughput alone as the story; it pairs flow with stability, recovery, and rework."}),"\n",(0,r.jsx)(t.p,{children:"So the problem is no longer just that some metrics are incomplete."}),"\n",(0,r.jsx)(t.h2,{id:"your-dashboard-is-probably-measuring-the-wrong-layer",children:"Your dashboard is probably measuring the wrong layer"}),"\n",(0,r.jsx)(t.p,{children:"Most engineering dashboards still focus on the production layer of software delivery."}),"\n",(0,r.jsx)(t.p,{children:"They measure how much work was opened, merged, deployed, closed, or shipped. They measure movement. They measure the existence of artifacts. They measure the part of the system AI happens to accelerate most visibly."}),"\n",(0,r.jsx)(t.p,{children:"But that is no longer where the real bottleneck lives."}),"\n",(0,r.jsx)(t.p,{children:"The real bottleneck keeps moving toward validation, judgment, integration, correction, coordination, and confidence. It moves into the layer where teams have to decide whether generated work is correct, safe, coherent, maintainable enough, and worth the operational cost it introduces downstream."}),"\n",(0,r.jsx)(t.p,{children:"And that layer is barely visible in most dashboards."}),"\n",(0,r.jsx)(t.p,{children:"This is why a team can now look dramatically faster at the production layer while becoming slower at the system layer. The dashboard shows acceleration. The organization experiences friction."}),"\n",(0,r.jsx)(t.p,{children:"That friction is not abstract. Research on collaboration overload found that collaborative activities can consume around 80% of time in many companies, often concentrated in a small fraction of people. Microsoft 365 telemetry has also shown workers being interrupted roughly every two minutes by meetings, email, or notifications. In that environment, generating more artifacts does not automatically improve delivery. It can simply create more things to review, more decisions to validate, and more noise for the system to absorb."}),"\n",(0,r.jsx)(t.p,{children:"That is why AI-era dashboards are so risky. They often reward the layer that became cheaper while ignoring the layer that became more expensive."}),"\n",(0,r.jsx)(t.p,{children:"A team can look more productive because it opened more PRs, shipped more changes, or closed more work. Meanwhile, the hidden cost shows up somewhere else: review latency, rollback pressure, approval wait time, clarification loops, unplanned follow-up work, or operational cleanup. If you only watch the visible layer, you miss whether the system is actually converting activity into trusted outcomes."}),"\n",(0,r.jsx)(t.h2,{id:"what-engineering-leaders-and-teams-should-measure-now",children:"What engineering leaders and teams should measure now"}),"\n",(0,r.jsx)(t.p,{children:"The answer is not to throw metrics away."}),"\n",(0,r.jsx)(t.p,{children:"The answer is to stop asking one class of metrics to do a job it cannot do."}),"\n",(0,r.jsx)(t.p,{children:"Throughput still matters. Lead time matters. Deployment frequency matters. Change volume can still tell you something. But those numbers should now be treated as clues, not verdicts. On their own, they no longer tell you enough about engineering performance. SPACE already warned against reducing productivity to a single number, and DORA already gave us a better model by pairing flow with stability and rework."}),"\n",(0,r.jsx)(t.p,{children:"What matters now is balancing production metrics with the metrics that reveal whether the organization actually metabolized the work well."}),"\n",(0,r.jsx)(t.p,{children:"First, measure validation and correction. Rework rate. Rollback rate. Escaped defects. Review latency. Approval wait time. Unplanned post-release work. These are no longer secondary signals. In the age of AI, they are the cost of turning generated output into trusted output."}),"\n",(0,r.jsx)(t.p,{children:"Second, measure coordination cost. Queue time between stages. Meeting load tied to delivery. Interrupt-driven work. Cross-team dependency delay. Repeated escalation loops. Clarification churn. These are not administrative side effects. They are part of system performance. Research on process debt in agile teams found that factors such as process unsuitability and role debt were significant predictors of lower job satisfaction, with the model explaining roughly one-third of the variance in job satisfaction across 191 participants in two organizations."}),"\n",(0,r.jsx)(t.p,{children:"Third, pull outcomes back to the center. Adoption. Retention. Reliability. Time-to-value. Revenue impact. Cost-to-serve. These are much harder to inflate with AI-generated activity. They force the conversation back to whether engineering changed anything meaningful at all. A mature dashboard should make it difficult to confuse reporting theater with customer impact."}),"\n",(0,r.jsx)(t.p,{children:"That is why a two-layer dashboard makes sense."}),"\n",(0,r.jsx)(t.p,{children:"One layer should be public and simple: a small set of delivery and outcome measures, the kind leaders can use to discuss performance without drowning everyone in instrumentation."}),"\n",(0,r.jsx)(t.p,{children:"The second layer should be diagnostic: meeting load, queue times, unplanned work share, rework, interruptions, and the other sources of friction that explain why the system feels slower than the surface metrics suggest. That layer is not for performance theater. It is for learning."}),"\n",(0,r.jsx)(t.h2,{id:"the-uncomfortable-reality--how-to-survive-it",children:"The Uncomfortable Reality & How-To Survive It"}),"\n",(0,r.jsx)(t.p,{children:"In the age of AI, the easiest thing to scale is visible activity."}),"\n",(0,r.jsx)(t.p,{children:"That is exactly why visible activity is becoming a dangerous thing to manage by."}),"\n",(0,r.jsx)(t.p,{children:"Teams will look faster. Dashboards will look healthier. Leadership updates will sound more convincing. And underneath all of that, the system may be carrying more rework, more coordination drag, more review burden, and less real confidence than ever."}),"\n",(0,r.jsx)(t.p,{children:"That is the trap."}),"\n",(0,r.jsx)(t.p,{children:"Not that AI will make mediocre teams look productive."}),"\n",(0,r.jsx)(t.p,{children:"That leadership will reward the appearance of progress while the real bottlenecks move somewhere else."}),"\n",(0,r.jsx)(t.p,{children:"The organizations that win will not be the ones that generate the most."}),"\n",(0,r.jsx)(t.p,{children:"They will be the ones disciplined enough to see past the noise, measure what still matters, and refuse to confuse activity with performance."})]})}function d(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,r.jsx)(t,{...e,children:(0,r.jsx)(c,{...e})}):c(e)}},8453(e,t,n){n.d(t,{R:()=>o,x:()=>s});var i=n(6540);const r={},a=i.createContext(r);function o(e){const t=i.useContext(a);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:o(e.components),i.createElement(a.Provider,{value:t},e.children)}},4897(e){e.exports=JSON.parse('{"permalink":"/blog/2026/05/05/our-engineering-metrics-are-about-to-get-even-more-misleading-in-the-age-of-ai","editUrl":"https://github.com/alvarolorentedev/website/tree/main/blog/2026-05-05-our-engineering-metrics-are-about-to-get-even-more-misleading-in-the-age-of-ai.md","source":"@site/blog/2026-05-05-our-engineering-metrics-are-about-to-get-even-more-misleading-in-the-age-of-ai.md","title":"Our Engineering Metrics Are About to Get Even More Misleading in the Age of AI","description":"The more AI increases visible activity, the less visible activity tells us about real engineering performance.","date":"2026-05-05T00:00:00.000Z","tags":[{"inline":true,"label":"substack","permalink":"/blog/tags/substack"}],"readingTime":5.37,"hasTruncateMarker":true,"authors":[{"name":"Alvaro Jose","title":"Fractional CTO & Founder","url":"https://github.com/alvarolorentedev","imageURL":"https://avatars.githubusercontent.com/u/3071208","key":"alvarolorentedev","page":null}],"frontMatter":{"title":"Our Engineering Metrics Are About to Get Even More Misleading in the Age of AI","description":"The more AI increases visible activity, the less visible activity tells us about real engineering performance.","authors":"alvarolorentedev","tags":["substack"],"draft":false,"series":"","canonical_url":"https://theengineeringtax.com/p/our-metrics-are-about-to-get-even","cover_image":null},"unlisted":false,"prevItem":{"title":"The Hardest Part of AI Is Letting Go of Our Ego","permalink":"/blog/2026/05/13/the-hardest-part-of-ai-is-letting-go-of-our-ego"},"nextItem":{"title":"QA Engineering Won the War Why AI Is Shifting Engineering From Building to Validation","permalink":"/blog/2026/04/29/qa-engineering-won-the-war-why-ai-is-shifting-engineering-from-building-to-validation"}}')}}]);